async (params, browser) => {
  // Open page
  await browser.open('https://app.todoist.com/app/filters-labels')

  // Wait for content
  await browser.waitForSelector('a[href*="/label/"], [class*="label"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const labels = Array.from(document.querySelectorAll('a[href*="/label/"], [class*="label_item"]')).map(el => { const name = el.textContent?.trim()||''; const count = el.querySelector('.count, [class*="count"]')?.textContent?.trim()||''; return { name, task_count: count }; }).filter(l=>l.name&&l.name.length<100); return { labels }`)

  return page_data
}
